async (params, browser) => {
  // Open product page
  await browser.open(`${params.product_url}`)

  // Wait for page
  await browser.waitForSelector('h1, [class*=\'product-title\'], [class*=\'Title\']', 15000)

  // Let page render
  await browser.wait(2000)

  // Scroll for content
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Scroll further
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Extract product details
  const product_data = await browser.evaluate(`const titleEl = document.querySelector('h1, [class*="product-title"], [class*="Title"]'); const priceEl = document.querySelector('[class*="product-price"], [class*="Price"], [class*="uniform-banner-box"]'); const ratingEl = document.querySelector('[class*="rating"], [class*="star"]'); const ordersEl = document.querySelector('[class*="sold"], [class*="trade"]'); const descEl = document.querySelector('[class*="product-description"], [class*="detail-desc"]'); const storeNameEl = document.querySelector('[class*="store-name"], a[href*="/store/"]'); const storeFeedbackEl = document.querySelector('[class*="store-feedback"], [class*="store-rating"]'); const specs = {}; document.querySelectorAll('[class*="specification"] li, [class*="product-prop"] li, [class*="property-item"]').forEach(function(el) { const text = el.textContent.trim(); const parts = text.split(':'); if (parts.length === 2) { specs[parts[0].trim()] = parts[1].trim(); } }); const images = []; document.querySelectorAll('[class*="slider"] img, [class*="image-view"] img, [class*="magnifier"] img').forEach(function(img) { const src = img.getAttribute('src') || ''; if (src && !images.includes(src)) images.push(src); }); const shippingEl = document.querySelector('[class*="shipping"], [class*="delivery"]'); return { title: titleEl ? titleEl.textContent.trim() : '', price: priceEl ? priceEl.textContent.trim() : '', rating: ratingEl ? ratingEl.textContent.trim() : '', orders: ordersEl ? ordersEl.textContent.trim() : '', description: descEl ? descEl.textContent.trim().substring(0, 1500) : '', store_name: storeNameEl ? storeNameEl.textContent.trim() : '', store_feedback: storeFeedbackEl ? storeFeedbackEl.textContent.trim() : '', shipping: shippingEl ? shippingEl.textContent.trim() : '', specifications: specs, images: images.slice(0, 8), url: window.location.href }`)

  return product_data
}
